| -- TRIGGER: trg_preregistrations_updated_at ON preregistrations
CREATE TRIGGER trg_preregistrations_updated_at BEFORE UPDATE ON preregistrations FOR EACH ROW EXECUTE FUNCTION update_modified_column();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          |
