| -- TRIGGER: trg_saving_types_updated_at ON saving_types
CREATE TRIGGER trg_saving_types_updated_at BEFORE UPDATE ON saving_types FOR EACH ROW EXECUTE FUNCTION update_modified_column();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          |
