| -- TRIGGER: trg_subscriptions_audit ON subscriptions
CREATE TRIGGER trg_subscriptions_audit AFTER INSERT ON subscriptions FOR EACH ROW EXECUTE FUNCTION log_subscription_change();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                |
