CREATE TRIGGER trg_apply_savings AFTER INSERT ON transactions FOR EACH ROW EXECUTE FUNCTION apply_transaction_savings();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            |
